test("casts over an instance of Branch", () => {
  const theBranch =
    TestCommonJsonization.loadMinimalBranch();

  expect(
    AasTypes.isNode(theBranch)
  ).toStrictEqual(true);
  expect(
    AasTypes.asNode(theBranch)
  ).toStrictEqual(theBranch);

  expect(
    AasTypes.isBranch(theBranch)
  ).toStrictEqual(true);
  expect(
    AasTypes.asBranch(theBranch)
  ).toStrictEqual(theBranch);

  expect(
    AasTypes.isLeaf(theBranch)
  ).toStrictEqual(false);
  expect(
    AasTypes.asLeaf(theBranch)
  ).toBeNull();

  expect(
    AasTypes.isBlossom(theBranch)
  ).toStrictEqual(false);
  expect(
    AasTypes.asBlossom(theBranch)
  ).toBeNull();

  expect(
    AasTypes.isSomething(theBranch)
  ).toStrictEqual(false);
  expect(
    AasTypes.asSomething(theBranch)
  ).toBeNull();

  expect(
    AasTypes.isContainer(theBranch)
  ).toStrictEqual(false);
  expect(
    AasTypes.asContainer(theBranch)
  ).toBeNull();
});

